import{Handle}from"../primitives/Handle.js";class Log extends Handle{onblamready(){super.onblamready(),this.cumulative&&this.setAttribute("role","list")}handle(event){let eventData=event?.detail;if(!eventData)return;let data=this.prop?eventData[this.prop]:eventData;this.cumulative||(this.innerHTML=""),this.innerHTML+=`\n      <span ${this.cumulative?'role="listitem"':""}>\n        ${"object"==typeof data?JSON.stringify(data):data}\n      </span>\n    `}get cumulative(){return this.hasAttribute("cumulative")}set cumulative(value){this.toBoolean("cumulative",value)}}export{Log};